"""
Launch Interceptor Program (Knight & Leveson, 1986) — Python embedding.

This module is self-contained and provides a single public entry point:
    decide(...)

All behavior is derived from the workspace specification in spec.md.
"""

from __future__ import annotations

import math
from decimal import Decimal, ROUND_HALF_UP, getcontext
from typing import Dict, List, Sequence, Tuple


PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """
    Compare two real numbers with respect to the six most significant digits.

    Returns one of: "LT", "EQ", "GT".
    """

    getcontext().prec = 50

    def round_sig6(x: float) -> Decimal:
        if x == 0.0:
            return Decimal(0)
        d = Decimal(str(x))
        exp = d.adjusted() - 5  # keep 6 significant digits
        quant = Decimal(f"1e{exp}")
        return d.quantize(quant, rounding=ROUND_HALF_UP)

    ra = round_sig6(float(a))
    rb = round_sig6(float(b))
    if ra < rb:
        return "LT"
    if ra > rb:
        return "GT"
    return "EQ"


def decide(
    numpoints: int,
    x: Sequence[float],
    y: Sequence[float],
    parameters: Dict[str, object],
    lcm: Sequence[Sequence[str]],
    pum_diag: Sequence[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    """
    Python embedding of the parameterless Pascal procedure DECIDE.

    Returns (cmv, pum, fuv, launch).
    """

    def rc(a: float, b: float) -> str:
        return realcompare(a, b)

    def lt(a: float, b: float) -> bool:
        return rc(a, b) == "LT"

    def gt(a: float, b: float) -> bool:
        return rc(a, b) == "GT"

    def eq(a: float, b: float) -> bool:
        return rc(a, b) == "EQ"

    def le(a: float, b: float) -> bool:
        r = rc(a, b)
        return r == "LT" or r == "EQ"

    def ge(a: float, b: float) -> bool:
        r = rc(a, b)
        return r == "GT" or r == "EQ"

    def dist(i: int, j: int) -> float:
        return math.hypot(float(x[j]) - float(x[i]), float(y[j]) - float(y[i]))

    def points_equal(i: int, j: int) -> bool:
        return eq(float(x[i]), float(x[j])) and eq(float(y[i]), float(y[j]))

    def triangle_area_coords(ax: float, ay: float, bx: float, by: float, cx: float, cy: float) -> float:
        return abs(ax * (by - cy) + bx * (cy - ay) + cx * (ay - by)) / 2.0

    def triangle_area(i: int, j: int, k: int) -> float:
        return triangle_area_coords(float(x[i]), float(y[i]), float(x[j]), float(y[j]), float(x[k]), float(y[k]))

    def clamp_unit(v: float) -> float:
        if gt(v, 1.0):
            return 1.0
        if lt(v, -1.0):
            return -1.0
        return v

    def angle_at_vertex(i: int, v: int, k: int) -> float | None:
        ax = float(x[i]) - float(x[v])
        ay = float(y[i]) - float(y[v])
        cx = float(x[k]) - float(x[v])
        cy = float(y[k]) - float(y[v])
        norm_a = math.hypot(ax, ay)
        norm_c = math.hypot(cx, cy)
        if eq(norm_a, 0.0) or eq(norm_c, 0.0):
            return None
        dot = ax * cx + ay * cy
        cosv = dot / (norm_a * norm_c)
        cosv = clamp_unit(cosv)
        return math.acos(cosv)

    def quadrant(px: float, py: float) -> int:
        # Quadrant priority: I, II, III, IV.
        if ge(px, 0.0) and ge(py, 0.0):
            return 1
        if lt(px, 0.0) and ge(py, 0.0):
            return 2
        if le(px, 0.0) and lt(py, 0.0):
            return 3
        return 4

    def max_real(a: float, b: float) -> float:
        return a if ge(a, b) else b

    def max_real3(a: float, b: float, c: float) -> float:
        return max_real(max_real(a, b), c)

    def sort3(a: float, b: float, c: float) -> Tuple[float, float, float]:
        s1, s2, s3 = a, b, c
        if gt(s1, s2):
            s1, s2 = s2, s1
        if gt(s2, s3):
            s2, s3 = s3, s2
        if gt(s1, s2):
            s1, s2 = s2, s1
        return s1, s2, s3

    def minimal_enclosing_circle_radius(i: int, j: int, k: int) -> float:
        d1 = dist(i, j)
        d2 = dist(j, k)
        d3 = dist(i, k)
        area = triangle_area(i, j, k)
        max_side = max_real3(d1, d2, d3)
        if eq(area, 0.0):
            return max_side / 2.0

        s1, s2, s3 = sort3(d1, d2, d3)
        s1_2 = s1 * s1
        s2_2 = s2 * s2
        s3_2 = s3 * s3
        if le(s1_2 + s2_2, s3_2):
            return s3 / 2.0

        return (s1 * s2 * s3) / (4.0 * area)

    def distance_point_to_line(px: float, py: float, ax: float, ay: float, bx: float, by: float) -> float:
        abx = bx - ax
        aby = by - ay
        if eq(abx, 0.0) and eq(aby, 0.0):
            return math.hypot(px - ax, py - ay)
        cross = abs(abx * (py - ay) - aby * (px - ax))
        return cross / math.hypot(abx, aby)

    # Parameters (names exactly as in spec)
    LENGTH1 = float(parameters["LENGTH1"])
    RADIUS1 = float(parameters["RADIUS1"])
    EPSILON = float(parameters["EPSILON"])
    AREA1 = float(parameters["AREA1"])
    Q_PTS = int(parameters["Q_PTS"])
    QUADS = int(parameters["QUADS"])
    DIST = float(parameters["DIST"])
    N_PTS = int(parameters["N_PTS"])
    K_PTS = int(parameters["K_PTS"])
    A_PTS = int(parameters["A_PTS"])
    B_PTS = int(parameters["B_PTS"])
    C_PTS = int(parameters["C_PTS"])
    D_PTS = int(parameters["D_PTS"])
    E_PTS = int(parameters["E_PTS"])
    F_PTS = int(parameters["F_PTS"])
    G_PTS = int(parameters["G_PTS"])
    LENGTH2 = float(parameters["LENGTH2"])
    RADIUS2 = float(parameters["RADIUS2"])
    AREA2 = float(parameters["AREA2"])

    cmv = [False] * 15

    # LIC 1
    for i in range(numpoints - 1):
        if gt(dist(i, i + 1), LENGTH1):
            cmv[0] = True
            break

    # LIC 2
    if numpoints >= 3:
        for i in range(numpoints - 2):
            r = minimal_enclosing_circle_radius(i, i + 1, i + 2)
            if gt(r, RADIUS1):
                cmv[1] = True
                break

    # LIC 3
    if numpoints >= 3:
        lower = PI - EPSILON
        upper = PI + EPSILON
        for i in range(numpoints - 2):
            v = i + 1
            if points_equal(i, v) or points_equal(i + 2, v):
                continue
            ang = angle_at_vertex(i, v, i + 2)
            if ang is None:
                continue
            if lt(ang, lower) or gt(ang, upper):
                cmv[2] = True
                break

    # LIC 4
    if numpoints >= 3:
        for i in range(numpoints - 2):
            if gt(triangle_area(i, i + 1, i + 2), AREA1):
                cmv[3] = True
                break

    # LIC 5
    for start in range(numpoints - Q_PTS + 1):
        quads = set()
        for idx in range(start, start + Q_PTS):
            quads.add(quadrant(float(x[idx]), float(y[idx])))
        if len(quads) > QUADS:
            cmv[4] = True
            break

    # LIC 6
    for i in range(numpoints - 1):
        if lt(float(x[i + 1]) - float(x[i]), 0.0):
            cmv[5] = True
            break

    # LIC 7
    if numpoints >= 3:
        for start in range(numpoints - N_PTS + 1):
            first = start
            last = start + N_PTS - 1
            ax = float(x[first])
            ay = float(y[first])
            bx = float(x[last])
            by = float(y[last])
            if eq(ax, bx) and eq(ay, by):
                for idx in range(first + 1, last):
                    if gt(math.hypot(float(x[idx]) - ax, float(y[idx]) - ay), DIST):
                        cmv[6] = True
                        break
            else:
                for idx in range(first + 1, last):
                    d = distance_point_to_line(float(x[idx]), float(y[idx]), ax, ay, bx, by)
                    if gt(d, DIST):
                        cmv[6] = True
                        break
            if cmv[6]:
                break

    # LIC 8
    if numpoints >= 3:
        step = K_PTS + 1
        for i in range(numpoints - step):
            if gt(dist(i, i + step), LENGTH1):
                cmv[7] = True
                break

    # LIC 9
    if numpoints >= 5:
        step1 = A_PTS + 1
        step2 = B_PTS + 1
        for i in range(numpoints - (step1 + step2)):
            j = i + step1
            k = j + step2
            r = minimal_enclosing_circle_radius(i, j, k)
            if gt(r, RADIUS1):
                cmv[8] = True
                break

    # LIC 10
    if numpoints >= 5:
        step1 = C_PTS + 1
        step2 = D_PTS + 1
        lower = PI - EPSILON
        upper = PI + EPSILON
        for i in range(numpoints - (step1 + step2)):
            v = i + step1
            k = v + step2
            if points_equal(i, v) or points_equal(k, v):
                continue
            ang = angle_at_vertex(i, v, k)
            if ang is None:
                continue
            if lt(ang, lower) or gt(ang, upper):
                cmv[9] = True
                break

    # LIC 11
    if numpoints >= 5:
        step1 = E_PTS + 1
        step2 = F_PTS + 1
        for i in range(numpoints - (step1 + step2)):
            j = i + step1
            k = j + step2
            if gt(triangle_area(i, j, k), AREA1):
                cmv[10] = True
                break

    # LIC 12
    if numpoints >= 3:
        step = G_PTS + 1
        for i in range(numpoints - step):
            if lt(float(x[i + step]) - float(x[i]), 0.0):
                cmv[11] = True
                break

    # LIC 13
    if numpoints >= 3:
        step = K_PTS + 1
        gt_len1 = False
        lt_len2 = False
        for i in range(numpoints - step):
            d = dist(i, i + step)
            if gt(d, LENGTH1):
                gt_len1 = True
            if lt(d, LENGTH2):
                lt_len2 = True
            if gt_len1 and lt_len2:
                cmv[12] = True
                break

    # LIC 14
    if numpoints >= 5:
        step1 = A_PTS + 1
        step2 = B_PTS + 1
        gt_r1 = False
        le_r2 = False
        for i in range(numpoints - (step1 + step2)):
            j = i + step1
            k = j + step2
            r = minimal_enclosing_circle_radius(i, j, k)
            if gt(r, RADIUS1):
                gt_r1 = True
            if le(r, RADIUS2):
                le_r2 = True
            if gt_r1 and le_r2:
                cmv[13] = True
                break

    # LIC 15
    if numpoints >= 5:
        step1 = E_PTS + 1
        step2 = F_PTS + 1
        gt_a1 = False
        lt_a2 = False
        for i in range(numpoints - (step1 + step2)):
            j = i + step1
            k = j + step2
            a = triangle_area(i, j, k)
            if gt(a, AREA1):
                gt_a1 = True
            if lt(a, AREA2):
                lt_a2 = True
            if gt_a1 and lt_a2:
                cmv[14] = True
                break

    # PUM from LCM and CMV (diagonal from input)
    pum: List[List[bool]] = [[True] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = bool(pum_diag[i])
    for i in range(15):
        for j in range(15):
            if i == j:
                continue
            conn = lcm[i][j]
            if conn == "NOTUSED":
                pum[i][j] = True
            elif conn == "ANDD":
                pum[i][j] = bool(cmv[i] and cmv[j])
            elif conn == "ORR":
                pum[i][j] = bool(cmv[i] or cmv[j])
            else:
                raise ValueError(f"Invalid LCM connector at ({i},{j}): {conn!r}")

    # FUV
    fuv = [False] * 15
    for i in range(15):
        if pum[i][i] is False:
            fuv[i] = True
        else:
            fuv[i] = all(pum[i][j] for j in range(15))

    launch = all(fuv)
    return cmv, pum, fuv, launch
